var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제 7방위선, 거점 기지","JPN":"人類統合防衛軍第7防衛線、拠点基地","ENG":"Base, United Humankind Defense Force's 7th Defense Line","TWN":"人類共同保衛軍第七防線基地"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그 뒤로 벌써 보름이나 지났는데, 본부에선 뭔가 알아낸 게 있나요?","JPN":"あれからもう半月経ちますが、本部の方では何か進展があったんでしょうか？","ENG":"It's been 2 weeks already. Has HQ found out anything yet?","TWN":"都已經過去半個月了，總部那邊都沒有什麼發現嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아니요. 예상대로 우리 세계의 기술력으로는 프로텍트를 해제할 수 없는 모양이에요.","JPN":"いいえ。予想通り、私たちの世界の技術力ではプロテクトを解除することはできないようです。","ENG":"No. As we expected, it is impossible to disable the protection with our technology.","TWN":"沒有，不出所料，以我們世界的技術還無法解除那些裝備上的防護器。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"무기를 함선 밖으로 반출하면 즉시 분자단위로 분해되어 쓸 수 없다는 보고를 받았거든요.","JPN":"武器を艦船の外に搬出すると、すぐに分子単位に分解され、使えなくなるという報告を受けました。","ENG":"According to reports, the weapons disintegrate into atoms the moment they are taken outside of the ship.","TWN":"而且我收到的報告說，若是將武器搬離艦船之外，會立刻分解成分子，無法使用。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하아, 역시 일이 그렇게 잘 풀릴 리 없겠죠.","JPN":"はぁ、やっぱりそう簡単にはいきませんよね。","ENG":"*Sigh...* I knew things weren't going to go so smoothly.","TWN":"哈啊，果然事情不會那麼順利。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그럼 결국 방법은 그 안토노프라는 분이 기억을 되찾는 수밖에 없겠네요.","JPN":"じゃあ結局、あのアントノフという人が記憶を取り戻すしか方法はないんですね。","ENG":"The only thing left is for Antonov to get her memories back.","TWN":"那麼，只剩下讓那位名叫安東諾夫的人，找回記憶這一個辦法了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그렇겠죠.","JPN":"そうですね。","ENG":"I suppose so.","TWN":"沒錯。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"따라서 당분간 제가 이곳 제7 방위선의 담당관이 되어, 그자를 내사하기로 결정했습니다.","JPN":"というわけで、当分は私がこの第7防衛線の担当官となり、彼女を内偵することにしました。","ENG":"So for the time being, I've decided to be in charge of the 7th Defense Line and investigate her myself.","TWN":"所以我會臨時擔任第七防線的負責人，並且親自對她展開調查。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"내사라고요? 사령 본부로 이송하지 않고?","JPN":"内偵？　指令本部に移送するんじゃなくて？","ENG":"Investigate her yourself? Why not hand her over to HQ?","TWN":"親自調查？不把她移交給司令總部嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우린 아직 그자가 어떤 의도로 우리 세계로 왔는지 모릅니다. 기억을 잃었다는 것 자체가 우리를 기만하는 걸지도 모르죠.","JPN":"私たちはまだ彼女がなぜ私たちの世界に来たのかわかっていません。記憶喪失もただの嘘なのかもしれませんし。","ENG":"We have no idea what her intentions are for coming to this world. Plus, her amnesia could just be a ploy to make us lower our guards.","TWN":"我們目前還不清楚，她是帶著什麼目的來到我們世界的。也許失憶這件事，本身就是個謊言。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"무엇보다도 그자에 관해서는 로스트 쉽이나 무기고 외에도 수상한 점이 많아요.","JPN":"なにより彼女に関しては、ロストシップや武器庫以外の点でも怪しいところが多いんです。","ENG":"But above all, there are many suspicious things about her other than the Lost Ship and the weapons.","TWN":"最重要的是，除了與她相關的失落艦船和那些武器外，還有許多其他可疑的部分。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그 외에 수상한 점?","JPN":"それ以外の怪しいところ？","ENG":"What are they?","TWN":"其他可疑的地方？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아시다시피 이면 세계든, 현실 세계든 각 세계 간에는 <color=#ffd34c>양자 위상의 차이</color>가 존재해요.","JPN":"ご存知のとおり、裏世界であれ現実世界であれ、世界と世界の間には<color=#ffd34c>量子位相のズレ</color>が存在します。","ENG":"As you know, there's a <color=#ffd34c>quantum phase difference</color> between worlds and even between Counterside and ours.","TWN":"你也知道不管是異界還是現實世界，每個世界之間都存在<color=#ffd34c>量子能量差</color>。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이 법칙을 무시하면 얼마 안 가 물질의 구성 원소가 유지력을 잃고 완전히 분해되어버리죠.","JPN":"この法則を無視すると、物質はやがて構成元素の維持力を失い、完全に分解されてしまいます。","ENG":"Ignoring this law will make any material lose its molecular structure and disintegrate.","TWN":"如果無視這個規律，物質的構成元素很快就會失去穩定性，並完全分解掉。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"하지만 그 엑자일러는 어떻죠? ","JPN":"しかしあのエグザイラーはどうでしょうか？ ","ENG":"But, what about the Exile?","TWN":"但那個流浪者呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"벌써 보름이나 지났는데 사라지지 않았잖아요.","JPN":"半月も経つのに、まだ消えていません。","ENG":"It's been over 2 weeks and she's still here.","TWN":"已經過去半個月了，她卻沒有消失。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"듣고 보니, 확실히 이상하네요.","JPN":"そう言われてみれば、確かに変ですね。","ENG":"Now that you mention it, that is certainly odd.","TWN":"聽你這麼一說，確實有點可疑。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그 말은 즉, 엑자일러가 다른 세계에 정착할 수 있다는 뜻이잖아요.","JPN":"つまりそれは、エグザイラーが別の世界に定着することができるということを意味しますよね。","ENG":"That can only mean that Exiles can migrate to other worlds.","TWN":"你的意思就是，流浪者也可以在其他的世界定居。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네, 틀림없이 그자는 우리보다 많은 걸 알고 있을 겁니다.","JPN":"はい、間違いなく彼女は私たちより多くのことを知っているはずです。","ENG":"Yes. I'm sure that she knows more than we can ever imagine.","TWN":"沒錯。而且她知道的好像比我們更多。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저는 무슨 짓을 해서라도 그자가 우리 세계에 온 목적을 알아내고야 말 겁니다.","JPN":"私は何としてでも、彼女が私たちの世界に来た目的を聞き出してみせます。","ENG":"My objective with her is to find out why she's here, no matter what it takes.","TWN":"無論如何，我都要弄清楚她來我們世界的目的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하지만 괜찮겠어요, 카린 양?","JPN":"でも、そんなことをして大丈夫なんですか、カリンさん？","ENG":"But are you sure about this, Karin?","TWN":"你確定嗎，卡琳？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아마도 그 안토노프라는 엑자일러, 다른 세계에선 델타 세븐의 대원이었던 것 같던데요?","JPN":"おそらくあのアントノフというエグザイラーは他の世界ではデルタセブンの隊員ですよ？","ENG":"That Exile, Antonov, looked like a member of Delta Seven from another world, no?","TWN":"也許那個叫做安東諾夫的流浪者，曾是其他世界第七三角洲部隊的隊員呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그런 건 상관없습니다.","JPN":"そんなのは関係ありません。","ENG":"That won't be an issue.","TWN":"這個不是問題。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저라면, 그런 사사로운 감정에 휘둘릴 리 없으니까요!","JPN":"私はそんな些細な感情には振り回されませんから！","ENG":"Because I'm not one to be swayed by emotions!","TWN":"我不會被這種私人感情而左右！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"subtitle","speaker":null,"text":{"KOREA":"1년 뒤","JPN":"一年後","ENG":"1 year later.","TWN":"1年後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제7 방위선 거점 기지, 민간 거주 셸터","JPN":"人類統合防衛軍第7防衛線拠点基地、民間居住シェルター","ENG":"Residence Shelter, United Humankind Defense Force's 7th Defense Line","TWN":"人類共同保衛軍第七防線基地，住民庇護中心"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"의약품이랑, 배수용 파이프…… 그리고 정수장치와 당근 모종 말씀입니까?","JPN":"医薬品と、配水用のパイプ……そして浄水装置とニンジンの苗木ですか？","ENG":"Medicine, a drainage pipe... a water purifier and carrot seeds. Is that correct?","TWN":"藥品、排水管……以及淨水裝置和胡蘿蔔苗，對嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L42_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"알겠습니다. 다음 보급 때, 소령님께 건의해보도록 하죠.","JPN":"わかりました。次回の補給の際に少佐に取り合ってみます。","ENG":"Understood. I'll suggest them to the major on my next supply run.","TWN":"我明白了，下次補給時，我會向少校報告的。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"아유, 고마워요. 안토노프 행정관님이 없었으면 불편해서 어떻게 살았을지 몰라.","JPN":"まあ、ありがとうね。アントノフ行政官がいなかったら、ここはかなり不便だったろうねえ。","ENG":"Oh, thank you. I don't know what we'd do without you, Officer Antonov.","TWN":"哎呀，真是太感謝了！如果沒有安東諾夫行政官，我都不知道該怎麼活下去。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"아닙니다. 군인으로서 당연한 의무인걸요.","JPN":"いいえ。軍人として当然の義務ですから。","ENG":"You don't have to thank me. I'm just doing my job as a soldier.","TWN":"不用謝，作為一名軍人，這是我應盡的義務。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"오히려 감사는 제가 드리고 싶군요.","JPN":"むしろ私の方こそ感謝いたします。","ENG":"Actually, I should be the one thanking you.","TWN":"反而是我應該向你表示感謝。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"인프라가 구축된 1지구 거주권을 포기하시고 굳이 최전선의 7지구를 선택하셨으니까요.","JPN":"インフラが整った第1地区の居住権を諦めて、あえて最前線である第7地区を選んでくださったではないですか。","ENG":"You chose to give up your residence in the well-infrastructured District 1 and move to the frontlines of District 7.","TWN":"你放棄了基礎設施完善的第一區居住權，堅定選擇了處於最前線的第七區。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"혹시 뭔가 특별한 이유라도 있으신겁니까?","JPN":"何か特別な理由でもおありだったのですか？","ENG":"May I ask if there was a specific reason for doing so?","TWN":"是有什麼特別的原因嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"그게 별 건 아니고, 사실 여기가 원래 내 고향이었거든.","JPN":"別に大した理由じゃないんだけれど、実はここが私の故郷なのよ。","ENG":"Oh, it's nothing special. You see, this is my hometown.","TWN":"呵呵，沒什麼特別的，實際上這裡才是我的家鄉。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"고향이요?","JPN":"故郷？","ENG":"Your hometown?","TWN":"你的家鄉？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"저기 방위선 기지가 있던 곳에는 원래 커다란 쇼핑몰이 있었고. 저 방벽 너머에는 역이 있었지. 내가 거기서 근무했었고.","JPN":"あそこの防衛線の基地があった場所にはもともと大きなショッピングモールがあってねえ。あの防壁の向こう側には駅があって、私はそこで昔働いていたのよ。","ENG":"Right there, where the base is, there used to be a huge shopping mall. And over the wall, there was a station. I know because I used to work there.","TWN":"我記得啊，防線基地所在的地方，原來是一座大型購物中心。那個屏障後面原先有個車站，我曾經就在那裡工作。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그렇군요.","JPN":"なるほど。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"후후, 사람이라는 게 결국 자기가 태어나고 자란 땅을 기억할 수밖에 없는 것 같아.","JPN":"ふふ、人は結局自分の生まれ育った土地は忘れられないのね。","ENG":"Ha ha. It just goes to show that people have no choice but to remember where they were born and raised.","TWN":"呵呵，人啊，到最後懷念的只有自己出生長大的地方。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"죽을 때가 다 된 건지…… 그 시절 추억이 아른아른 떠올라서…….","JPN":"お迎えが来る日が近いのか……昔の思い出を色々思い出しちゃって……","ENG":"Maybe my time is coming to an end... I keep feeling nostalgic about the old days...","TWN":"也許是我的時間快到了……以前的記憶總是在腦海隱隱約約地浮現……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"이곳을 버리지 않고, 살 수 있게 만들어준 자네들이 나는 늘 고마워요.","JPN":"ここを捨てずに、暮らせるようにしてくれたあなたたちにはいつも感謝していますよ。","ENG":"So, I'm grateful that you didn't abandon this place and made it habitable again.","TWN":"我一直很感謝你們，沒有放棄這個地方，讓我能在這裡生活。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"아, 그러고 보니 안토노프 행정관님은 고향이 어디라고 했더라?","JPN":"ああ、そういえばアントノフ行政官の故郷はどこと言っていたかしら？","ENG":"Oh, that's right. Where did you say your home was, Officer Antonov?","TWN":"啊，我還沒問過……安東諾夫行政官的家鄉在哪裡？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"아, 저는…….","JPN":"あ、私は……","ENG":"Oh, I...","TWN":"啊，我……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BOY_EXILER_NPC_NULL","text":{"KOREA":"할머니! 나 배고파요!","JPN":"お祖母ちゃん！　お腹空いちゃった！","ENG":"Grammy! I'm hungry!","TWN":"奶奶！我餓了！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"아이고, 내 정신 좀 봐! 우리 손주 밥시간이 다 됐네.","JPN":"おお、ごめんねえ！　もうご飯の時間だったね。","ENG":"Oh dear! Look at the time! It's time to feed my grandson already.","TWN":"呵呵，瞧我這記性！都快到孫子吃飯的時間了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"행정관님, 기지로 돌아가기 전에 우리 집에 들러서 순무 좀 가져가요.","JPN":"行政官、基地に戻られる前に家に寄っていってくださいな、カブをお渡ししたいわ。","ENG":"Officer Antonov, please come over to my house for some turnips before going back to base.","TWN":"行政官，來我們家拿些蕪菁再走吧。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"아뇨! 괜찮습니다. 대가를 바라고 한 행동이 아닙니다.","JPN":"いいえ！　大丈夫です。見返りを期待してのことではありませんので。","ENG":"Oh, that's okay. We don't do this to get anything in return.","TWN":"不用了！沒關係的，我們不是為了得到回報才這樣做的。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"그러지 말고. 신세를 졌으면 원래 갚아야 하는 거야.","JPN":"そう言わずに。親切にしてもらったからには、お礼をしなくちゃ。","ENG":"Please. It's only fair to repay the people who help you.","TWN":"你就別推辭了，受到你們的照顧，報答是應該的。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그, 그렇다면……","JPN":"そ、そうおっしゃるなら……","ENG":"I-if you insist...","TWN":"那，那就……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"순무는 싫어!","JPN":"カブは嫌！","ENG":"I HATE TURNIPS!!","TWN":"我討厭蕪菁！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"순무 빵, 순무 스프, 순무 샐러드, 순무 조림 심지어 순무 스테이크까지!!","JPN":"カブのパンに、カブのスープ、カブのサラダ、カブの煮込みに、カブステーキまで！！","ENG":"Turnip bread, turnip soup, turnip salad, braised turnip, and even turnip steak!!","TWN":"蕪菁麵包、蕪菁湯、蕪菁沙拉、燉蕪菁、竟然還有蕪菁排！？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"이러다가 정수리에서 머리카락 대신 잎사귀가 자랄 지경이라고!","JPN":"このまま行けばじきに頭のてっぺんから、髪の毛じゃなくて葉っぱが生えくるわ！","ENG":"At this rate, I'll be growing turnip leaves on my head instead of hair!","TWN":"再這樣吃下去，我的頭上都要長蕪菁葉子了！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"사이버 캣, 이 순무는 셸터 주민분들이 직접 재배한 소중한 식량입니다.","JPN":"サイバーキャット、このカブはシェルターの住民の方々が栽培された大事な食糧なんですよ。","ENG":"Cyber Cat, these turnips are precious rations the shelter residents farmed on their own.","TWN":"賽博貓，這些蕪菁是庇護中心的居民親自種植的寶貴糧食。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그러니까 하나도 남기지 말고 꼭꼭 씹어서 먹도록 해요.","JPN":"ですから、残さずによく味わって食べてくださいね。","ENG":"Make sure to eat every last bit so it doesn't go to waste.","TWN":"所以，一點也不能浪費。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"우이씨! 요새 소령이 잠잠하니까, 새로운 잔소리꾼이 나타났네!","JPN":"もうっ！　最近少佐の小言が減ったかと思ったら、別の小言屋が出てきた！","ENG":"Ugh! We got ourselves another nagger since Major isn't anymore!","TWN":"哼！最近少校不嘮叨了，又出現了個新的嘮叨鬼！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"알고 있어? 난 정식 대원은 아니지만 따지고 보면, 나는 행정관인 너보다 상관이라고?","JPN":"知ってる？　アタシは正式な隊員じゃないけど、厳密にいえば行政官のアンタより上司なのよ？","ENG":"Did you know this? I may not be an official member, but I do outrank you!","TWN":"你知不知道？雖然我不是正式隊員，但真要說起來，我可是你的上司！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"다시 말해, 이건 하극상이자 아동학대야!","JPN":"もう一度言うわ、これは下剋上であり、児童虐待よ！","ENG":"In other words, this is child abuse and mutiny, I tell you!","TWN":"換句話說，你這算是以下犯上兼虐待兒童！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"아니요. 사이버캣은 군인이기 이전에 어린이입니다.","JPN":"いいえ。サイバーキャットは軍人である以前に、子どもです。","ENG":"No. You are a child before you are a soldier, Cyber Cat.","TWN":"這不算，賽博貓你作為軍人之前，首先是個孩子。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그리고 국가를 위해서 어린이의 가장 중요한 임무는 건강하게 잘 자라는 거죠.","JPN":"そして国にとって子どもの最も大事な任務は健やかに育つことです。","ENG":"And the most important mission for a child is to grow healthy and strong.","TWN":"為了國家，孩子最重要的任務就是健康成長。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"으아아! 이 잔소리 핵폭탄!","JPN":"うぎゃあ！　この小言核爆弾！","ENG":"Aaagh! It's a nuclear bomb of nagging!!","TWN":"啊啊啊！你的嘮叨程度根本就是核爆等級！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"카카오매스...... 설탕...... 생크림...... 가염버터......","JPN":"カカオマス……砂糖……生クリーム……有塩バター……","ENG":"Cacao mass... Sugar... Whipped cream... Salted butter...","TWN":"可可豆……砂糖……生奶油……加鹽奶油……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"그리고...... 바로 이것!","JPN":"そして……これ！","ENG":"And... This!","TWN":"還有……這個！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MONSTER_EXTRA_NULL_NULL","text":{"KOREA":"크르르르르르......","JPN":"グルルルルルル……","ENG":"Grrrrrrrr...","TWN":"卡啦啦啦啦啦……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_FALL_DAMAGE_DOWN"},{"id":"L44_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"후후...... 완벽해. 걸작이야. 드디어 내 연구가 결실을 맺게 됐어.","JPN":"ふふ……完璧かつ傑作だ。\\nやっと僕の研究が実を結んだんだ。","ENG":"Hah Hah... Perfect. It's a masterpiece. Finally, my research has come to fruition.","TWN":"嘿嘿……完美，這完全是傑作啊，我的研究終於有成果啦。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"마침 시간도 인간이 가장……","JPN":"しかも、時間も丁度、人間がもっとも……","ENG":"And today happens to be–","TWN":"還恰好是讓人變得最……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"로널드 박사님?","JPN":"ロナルド博士？","ENG":"Dr. Ronald Lee?","TWN":"羅那魯多博士？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"우갸아아악!?","JPN":"ぐぉおおおっ！？","ENG":"Uwaaagh?!","TWN":"哇啊啊啊？！"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"아, 아, 안토노프 양!? 여, 여, 여긴 어떻게!?","JPN":"あ、アントノフさん！？　な、な、なんでここに？","ENG":"A-A-Antonov?! W-w-why are you here?!","TWN":"啊啊，安東諾夫？！你，你，你怎麼在這裡？"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"네? 말씀하신 표본과 보고서 정리를 모두 마쳐서 보고하러 왔습니다.","JPN":"はい？　おっしゃっていた標本と報告書をまとめ終えたので、報告に来たのですが。","ENG":"Hmm? I'm here to report back because I have completed organizing the samples and reports you handed me.","TWN":"嗯？我來向你報告，之前你說的樣本和報告都整理完了。"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"얼레? 그거 5년치 자료였는데? 그 많은 걸 벌써 다했다고?","JPN":"え？　あれはたしか5年分の資料だったはずだけど？　それをもう終わらせたって？","ENG":"Huh? But that was five years' worth of data. You're already finished with it?","TWN":"蛤？那可是整整5年的資料啊？你全部都整理好了？"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"사무행정은 책상 위에서의 전쟁이니까요. 작전만 잘 세우면 승리할 수 있습니다.","JPN":"行政事務は机上での戦争ですからね。作戦をうまく立てれば勝利できます。","ENG":"Office administration is a war that happens on desks. With the right strategy, victory is achieved.","TWN":"行政事務就像是書桌上的戰爭。只要制定好作戰計畫，就能贏得勝利。"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그보다 박사님, 손에 든 그 열매는 뭔가요?","JPN":"それより博士、その手にある果実は何ですか？","ENG":"By the way, Doctor, what's that fruit in your hand?","TWN":"對了博士，你手上拿著的果實是什麼？"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"아! 이건 이면세계에서 자라는 솔로카오라는 열매인데 이걸 식용 초콜릿으로……","JPN":"ああ！　これは裏世界に生育するソロカオという果実なんだけど、これを食用のチョコレートにして……","ENG":"Oh! This is a fruit from Counterside called Solocao, and I've made it into an edible chocolate...","TWN":"啊！這是生長在異界的獨株可可，我把它做成了食用巧克力……"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"어이, 어이, 어이!! 잠깐! 로널드, 너 지금 미쳤어!?","JPN":"お、おい、おい！！　ちょっと待てよ！　ロナルド、お前イカれちゃったのか？","ENG":"Whoa, whoa, whoa!! Hold on! Are you crazy, Ronald?!","TWN":"喂、喂、喂！！等等！羅那魯多·李，你瘋了嗎！？"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L9_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"초콜릿으로 만든 침식체로 온 세상의 커플들을 박살 낼 계획을 지금 발설할 셈이야?","JPN":"チョコレートで作り出した侵食体で世の中のすべてのカップルを破綻させる計画を漏らそうとするなんて！","ENG":"Were you seriously gonna tell her about your plans to destroy all couples using a C.O. made from chocolate?!","TWN":"你現在是打算告訴大家，你準備用巧克力做的侵蝕體拆散全世界情侶的計畫嗎？"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"다른 사람도 아닌, 이 고지식한 안토노프 양한테?","JPN":"しかもよりによって、この頭の堅いアントノフさんに！","ENG":"Not just anyone, but the hardheaded Antonov?!","TWN":"還是對著死腦筋的安東諾夫？！"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"네? 침식된 토양에서 재배 가능한 식용 열매를 찾았다는 말씀입니까?","JPN":"はい？　侵食された土壌で栽培可能な食用果実を見つけられたんですか？","ENG":"Huh? Do you mean to say that you found a fruit that's capable of being farmed on Corrupted soil?","TWN":"嗯？你是說發現了可以栽種在被侵蝕的土壤裡的食用果實嗎？"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그건 엄청난 연구 성과입니다!","JPN":"それはすごい研究成果ですね！","ENG":"That is an incredible research accomplishment!","TWN":"這是一項了不起的研究成果！"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이거라면 인류의 식량난을 해결할 수 있어요! 당장, 소령님께 보고드리죠!","JPN":"これなら人類の食糧難を解決できますよ！　今すぐ、少佐に報告しましょう！","ENG":"This could mean the end of humankind's food crisis! Let's report this to Major immediately!","TWN":"這樣一來，人類的糧食危機就能得到解決了！我要馬上向少校報告！"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"어, 어어, 그게…….","JPN":"え、ああ、えっと……","ENG":"Uh, um, w-well...","TWN":"啊，啊啊，那個……"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"역시 믿고 있었습니다, 박사님. 당신은 세계 제일의 과학자예요!","JPN":"さすがです、博士。あなたは世界一の科学者です！","ENG":"I knew we could count on you, Doctor. You really are this world's best scientist!","TWN":"我就知道博士你一定可以做到。你是世界上最偉大的科學家！"},"stage":{"bg":"FACILITY","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"박사님? 갑자기 왜 말이 없으시죠?","JPN":"博士？　どうしていきなり無言になったのですか？","ENG":"Doctor? What's wrong? Why are you being so quiet?","TWN":"博士？你怎麼突然不說話了？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"아이의 첫 학교는 사립이 좋을까요? 공립이 좋을까요?","JPN":"子どもが入学する小学校は私立と公立、どっちがいいかな？","ENG":"Do you think it would be better to send our child to a private or public school?","TWN":"孩子的第一所學校是去私立好呢？還是去國立好呢？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"예? 박사님, 아이가 있으셨습니까?","JPN":"はい？　博士、お子さんがいらっしゃったんですか？","ENG":"What? Doctor, do you have kids?","TWN":"嗯？博士，你有孩子了嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"에!? 아, 아니, 아니! 그게 아니라!","JPN":"え？　い、いや、いや！　違うんだ！","ENG":"Huh?! N-no, that's not what I meant!","TWN":"嗯！？啊，不是，沒有！不是這樣的！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이건 1종 침식 경보?","JPN":"これは、第1種侵食警報？","ENG":"That's the alarm for a Category 1.","TWN":"這是1類侵蝕警報？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"잠깐, 이 시간대라면……!","JPN":"待てよ、この時間帯は……！","ENG":"Wait, what time is it...?!","TWN":"等等，這個時間的話……！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"위험해. 농장에 있는 거주민들을 빨리 피난시켜야 해.","JPN":"まずい。農場にいる住民たちを早く避難させなければ。","ENG":"This isn't good. The farming residents need to be evacuated this instant.","TWN":"糟糕，我得快點讓農場裡的居民去避難。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"박사님, 죄송하지만 먼저 실례하겠습니다!","JPN":"博士、申し訳ありません。お先に失礼します！","ENG":"Doctor, my apologies, but please excuse me!","TWN":"博士，很抱歉，我要先走了！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 안 돼. 몇 개월 동안 기른 소중한 작물들이…….","JPN":"そ、そんな。何か月もかけて育てた大切な作物が……","ENG":"Oh, no. The crops we've been growing for months...","TWN":"不，不！這是我們種了幾個月的珍貴糧食……"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"지금 작물 걱정할 때야! 빨리 도망치자고!","JPN":"今は作物の心配をしている場合じゃないだろ！　早く逃げようぜ！","ENG":"We don't have time to worry about crops! We need to run!","TWN":"現在是擔心作物的時候嗎！快跑吧！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"여러분, 곧 방위군이 도착할 겁니다!","JPN":"皆さん、もうすぐ防衛軍が到着します！","ENG":"Everyone, the Defense Force will be arriving shortly!","TWN":"各位，保衛軍即將抵達這裡！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이곳 농장은 폐기합니다! 모두 셸터로 피신하세요!","JPN":"こちらの農場は放棄します！　皆さん、シェルターにご避難ください！","ENG":"Abandon the farms! Everyone to the shelter!","TWN":"立刻放棄這個農場！請大家全部前往庇護中心避難！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"해, 행정관님! 안토노프 행정관님!!","JPN":"ぎょ、行政官！　アントノフ行政官！！","ENG":"O-Officer Antonov! Officer Antonov!!","TWN":"行，行政官！安東諾夫行政官！！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"어르신! 피가 많이 나잖아요! 빨리 셸터로 대피해서 치료를!","JPN":"お婆さん！　すごい出血です！　早くシェルターに避難して治療を！","ENG":"Ma'am! You're bleeding! Head to the shelter quickly and get treatment!","TWN":"夫人！你流了很多血！請快去庇護中心接受治療！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OLDMAN_VOICE_NULL_NULL","text":{"KOREA":"나, 나는 괜찮아! 그보다 우리 손주가! 손주가!","JPN":"わ、私は大丈夫！　それより孫が、私の孫が！","ENG":"I-I'm okay! But my grandson! My grandson!","TWN":"我，我沒事！可是我孫子！孫子他！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GIRL_EXILER_NPC_NULL","text":{"KOREA":"으아, 어떡해!","JPN":"ああ、どうしよう！","ENG":"Waah! What do we do?","TWN":"呃啊，我們現在該怎麼辦！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GIRL_EXILER_NPC_NULL","text":{"KOREA":"괜히 여기까지 따라왔다가 이게 뭐야!","JPN":"ついて来いっていうから来たのに、なんでこうなるの！","ENG":"So this is what I get for following you all the way out here?!","TWN":"早知道就不跟你到這裡來了！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BOY_EXILER_NPC_NULL","text":{"KOREA":"나, 나도 갑자기 침식체가 나타날 줄은 몰랐지!","JPN":"ぼ、僕だって侵食体が現れるとは思わなかったんだ！","ENG":"H-hey, who knew a C.O. would appear!","TWN":"我，我也不知道侵蝕體會突然出現啊！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GIRL_EXILER_NPC_NULL","text":{"KOREA":"저 문, 금방이라도 부서질 것 같아!","JPN":"あのドア、今にも壊れそう！","ENG":"The door... It's going to break open soon!","TWN":"那扇門好像撐不住了！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BOY_EXILER_NPC_NULL","text":{"KOREA":"괜찮아! 군인 아저씨들이 우릴 구하러 와줄 거야! 그때까지만 버티면 돼!","JPN":"大丈夫！　きっと軍人のおじさんたちが助けに来てくれる！　それまで持ちこたえよう！","ENG":"It's all right! The soldiers will come to save us! We just need to hold it together until then!","TWN":"沒事的！軍人叔叔會來救我們的！我們只要堅持到那個時候就行！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GIRL_EXILER_NPC_NULL","text":{"KOREA":"그, 그러니까 무슨 수로 버텨!","JPN":"だ、だから持ちこたえるってどうやって！","ENG":"B-but how do we do that?!","TWN":"是要怎麼堅持啊！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GIRL_EXILER_NPC_NULL","text":{"KOREA":"으앗! 문이 부서졌잖아! 이제 어떡해!","JPN":"きゃっ！　ドアが壊れちゃった！　どうしよう！","ENG":"Ack! The door's busted open! What do we do now?!","TWN":"呃啊！門壞了！現在該怎麼辦！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BOY_EXILER_NPC_NULL","text":{"KOREA":"그, 그건……","JPN":"そ、それは……","ENG":"Th-that's...","TWN":"那，那個……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"두 사람 다 제 뒤로 피해요!","JPN":"二人とも私の後ろに隠れてください！","ENG":"Both of you get behind me!","TWN":"你們二個，躲在我後面。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"BOY_EXILER_NPC_NULL","text":{"KOREA":"해, 행정관 누나!?","JPN":"ぎょ、行政官のお姉さん！？","ENG":"O-Officer Antonov?!","TWN":"行，行政官姊姊！？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"쳇, 역시 보통 탄환으로는 무리인가!","JPN":"ちっ、やはり普通の弾丸じゃ効かないか！","ENG":"Tch! Normal bullets don't work on them!","TWN":"哼，果然普通的子彈沒有用嗎！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GIRL_EXILER_NPC_NULL","text":{"KOREA":"군인 언니! 저기 봐!","JPN":"軍人のお姉さん！　あっちを見て！","ENG":"Miss! Look over there!","TWN":"軍人姊姊！那邊！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BOY_EXILER_NPC_NULL","text":{"KOREA":"행정관 누나한테서 떨어져! 이 괴물!","JPN":"お姉さんから離れて！　この化け物！","ENG":"Get away from Officer Antonov, you monster!","TWN":"離行政官姊姊遠一點！你這個怪物！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"무, 무슨!? 달려들어서는 안 됩니다! 물러나세요!","JPN":"な、なにを！？　近づいてはいけません！　下がってください！","ENG":"W-what?! What do you think you're doing?! Get back here!","TWN":"不行！？別過去！快回來！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"크윽…….","JPN":"くうっ……","ENG":"Kgh...","TWN":"咳……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"와주셨군요, 주시영 용병님.","JPN":"来てくださったんですね、アキヤマ・シノンさん。","ENG":"You came, Miss Shiyoung.","TWN":"你來了，周時雨傭兵。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"침식체가 달려드는데 겁도 없이 뛰어들다니, 보기보다 무모하시네요. 안토노프 행정관?","JPN":"襲ってくる侵食体に飛び込むなんて、案外無茶をするんですね。アントノフ行政官？","ENG":"Running straight toward a C.O.? You're more reckless than I thought, Antonov.","TWN":"面對排山倒海而來的侵蝕體，毫不畏懼地迎上去。你可比看起來要衝動呢，安東諾夫行政官？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"별 볼일 없긴 하지만…… 일단은 카운터이긴 하니까요.","JPN":"こんな私ですが……一応はカウンターですからね。","ENG":"I am still a Counter... Albeit not that strong.","TWN":"沒什麼大不了的……畢竟我是制裁者。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"아이가 죽는 것보다는 훨씬 낫겠죠.","JPN":"子どもを死なせるよりは遥かにマシです。","ENG":"It was better than to let the children die.","TWN":"總不能看著孩子受傷吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"BOY_EXILER_NPC_NULL","text":{"KOREA":"미, 미안해, 행정관 누나…….","JPN":"ご、ごめん、行政官のお姉さん……","ENG":"I-I'm sorry, Officer Antonov...","TWN":"對，對不起。行政官姊姊……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"아닙니다. 오히려 절 지켜주려고 하셨잖아요, 작은 기사님?","JPN":"いいえ。むしろ私を守ろうとしてくれたでしょう、小さな騎士さん？","ENG":"No need for an apology. You were just trying to save me, weren't you, Little Knight?","TWN":"不用道歉。你是想保護我，對嗎，小騎士？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"자, 이제 다들 셸터로 돌아가요. 모두 기다리고 있으니까.","JPN":"さあ、もうシェルターにお戻りください。皆さんが待っていますから。","ENG":"Now, get back to the shelter. Everyone is waiting for you.","TWN":"好了，我們現在回庇護中心吧。大家都在等著我們呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"……이상으로 금일, 제7지구의 행정 보고를 마치겠습니다.","JPN":"……以上で本日の第7地区に関する行政報告を終わります。","ENG":"...That will be all for today's District 7 briefing.","TWN":"……以上，就是今天的第七區的行政報告。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"카린 웡 소령님? 무슨 생각 하십니까?","JPN":"カリン・ウォン少佐？　何かお悩みでも？","ENG":"Major Karin Wong, what are you thinking about?","TWN":"卡琳少校？你在想什麼？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아, 아무것도 아니에요!","JPN":"い、いいえ、何でもありません！","ENG":"N-nothing!","TWN":"啊，沒什麼！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그보다 부상은 좀 어떠신가요? 많이 다치셨나요?","JPN":"それよりお怪我の方は大丈夫ですか？　酷くはありませんでしたか？","ENG":"But how about you? I heard you've been injured.","TWN":"對了，你的傷怎麼樣？傷得嚴重嗎?"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이 정도는 괜찮습니다.","JPN":"これくらい大したことありません。","ENG":"I'm fine.","TWN":"這種程度的傷沒有關係。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"하지만 방위선 거주민들의 사기가 걱정되는군요.","JPN":"でも防衛線近辺の住民たちの士気が気がかりです。","ENG":"But I'm worried about the residents living on the borders.","TWN":"但我有些擔心防線居民的士氣。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이제 막 토지 정화 작업이 끝나고, 순무 외에 다른 식량을 재배할 수 있게 되었는데…….","JPN":"土地の浄化作業を終えて、やっとカブ以外の食糧を栽培できるようになったところだったのに……","ENG":"We just finished purifying the soil so we could plant and harvest crops other than turnips...","TWN":"好不容易才結束了土地淨化工作，可以種植蕪菁以外的糧食了……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아니요. 쓰러진 건 다시 세우면 됩니다.","JPN":"いいえ。倒れたものは立て直せばいいんです。","ENG":"No problem. We can rebuild it if it falls.","TWN":"不。就算是跌倒了，重新站起來就好了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"불과 1년 전에 이 방위선을 되찾았을 땐, 이 땅도 침식으로 불모지 같았죠.","JPN":"つい1年前、この防衛線を取り戻した時は、この地も侵食のせいで不毛の地に思えました。","ENG":"Just a year ago, when we first reclaimed the Defense Line, the soil was barren from Corruption.","TWN":"1年前，我們剛奪回這個防線的時候，這裡還是被侵蝕的不毛之地。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"하지만 지금은 이렇게 어찌어찌 사람이 살 수 있는 땅이 되었습니다.","JPN":"しかし今は、こうしてなんとか人が住める土地になりましたよね。","ENG":"But now, it has become habitable land.","TWN":"但現在這裡地也成了可以居住的地方。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그렇군요. 제가 경솔했군요.","JPN":"そうですか。私の考えが浅かったようです。","ENG":"You're right. I was being rash.","TWN":"明白。是我太著急了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"다시 해보죠. 모두 힘을 합하면 할 수 있을 겁니다.","JPN":"やり直します。全員で力を合わせればやれるはずです。","ENG":"We can try again. With everyone's help, we'll be able to restore it.","TWN":"我們重新來過。只要大家齊心協力，一定能做到。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"안토노프 행정관.","JPN":"アントノフ行政官。","ENG":"Officer Antonov.","TWN":"安東諾夫行政官。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"애초에 당신이 이곳의 행정을 맡아주지 않았다면, 이렇게 빨리 방위선을 회복할 수 없었을 거예요.","JPN":"そもそもあなたがここの行政官じゃなかったら、防衛線をここまで早く回復させることはできませんでした。","ENG":"If you hadn't taken charge of this place, we wouldn't have been able to recover the Defense Line this fast.","TWN":"當初要不是由你負責這裡的行政事務，也不會這麼快就把防線重建起來。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"인정하죠. 당신은 무척 유능한 사람입니다.","JPN":"認めましょう。あなたは非常に優秀です。","ENG":"I'll admit it. You are exceptionally competent.","TWN":"你是一個非常有能力的人。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"무슨 말씀이시죠? 이건 방위선 모든 주민이 노력하여 이루어 낸 성과입니다.","JPN":"何をおっしゃるんですか？　これは防衛線の住民の方々全員の努力によるものです。","ENG":"What do you mean? These accomplishments were made by all of the residents in this area.","TWN":"別這麼說？防線得以重建是所有居民一起努力的結果。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"애초에 기억도, 갈 곳도 없는 처지인 저를 군에 받아주신 분은 소령님이지 않습니까?","JPN":"そもそも、記憶も行く当てもない私を軍に受け入れてくださったのは少佐ではありませんか？","ENG":"And it was you who gave me a spot in the army–someone with no recollection of herself or a place to go.","TWN":"當初是少校收留沒有記憶、無處可去的我的，不是嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"여전히 그 로스트 쉽이나 스스로의 과거에 대한 건 떠오르지 않나요?","JPN":"相変わらずあのロストシップや自分の過去について、何も思い出せませんか？","ENG":"Do you still not remember anything about the Lost Ship or your past?","TWN":"關於那艘失落艦船和你的過去，你還是什麼都想不起來嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"면목없습니다만, 그렇습니다.","JPN":"はい、面目ありません。","ENG":"Sorry, but I'm afraid not.","TWN":"很抱歉，是的。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아니요, 당신이 사과할 문제는 아닙니다. 오히려 사과할 사람은 저니까요.","JPN":"いいえ、あなたが謝ることではありません。むしろ謝るべきなのは私の方です。","ENG":"No, it's not something you should apologize for. I should be the one apologizing.","TWN":"不，你不用道歉。要道歉的人應該是我。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"네? 그게 무슨……?","JPN":"はい？　それはいったいどういう……？","ENG":"Excuse me? I don’t understand...","TWN":"嗯？什麼意思……？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그동안 당신의 행동을 보고 줄곧 고민해왔는데, 이제 사실을 말씀드릴 때가 된 것 같군요.","JPN":"あなたの行動を見ながらずっと悩んできましたが、もう真実をお話しする時だろうと思います。","ENG":"I've been watching and thinking about your actions all this time, and I think it's time I told you the truth.","TWN":"這段期間我一直在觀察和思考你的所作所為，或許，現在是該告訴你實情了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"안토노프 행정관, 당신은 사실…… 이 세계의 사람이 아닙니다.","JPN":"アントノフ行政官、実はあなたは……この世界の人間ではありません。","ENG":"Officer Antonov, you are... not from this world.","TWN":"安東諾夫行政官，其實你……不是這個世界的人。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"……그래서 저희는 당신이 기억을 되찾을 때까지 이곳에 머물게 했던 겁니다.","JPN":"……だからこそ、あなたが記憶を取り戻すまではここに留まるようにしました。","ENG":"...That is why we had you stay until you retrieved your memories.","TWN":"……所以我們才想把你留在這裡，直到你恢復記憶為止。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아니, 엄밀히 말하면 그동안 당신을 속이고 있었던 거죠.","JPN":"いいえ、厳密にいえば、ずっとあなたを騙していたんです。","ENG":"No, strictly speaking, we have been deceiving you.","TWN":"不，嚴格來說這段時間是我欺騙了你。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"20년 뒤 다가올 멸망을 막기 위해서.","JPN":"20年後に訪れる滅亡を食い止めるために。","ENG":"So we could prevent this world from destruction 20 years in the future.","TWN":"為了阻止20年後到來的滅亡。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그 작전으로부터 벌써 2년에 가까운 시간을 소비해버렸으니 실제로는 더 짧겠지만요.","JPN":"その作戦にもう2年近くの時間を費やしましたから、実際にはもっと短いでしょうね。","ENG":"We've already used up 2 years since that operation, so it'll be less than 20 in reality.","TWN":"而且從那場作戰算起，已經過了將近2年的時間。實際上已經不到20年了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그, 그렇다면 왜 이제와서 이런 이야기를 하는 겁니까?","JPN":"な、なら、なぜ今急に私にその話をされるんですか？","ENG":"Th-then why are you telling me this now?","TWN":"那，那樣的話，為什麼要現在告訴我這些？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"굳이 저에게 진실을 전할 필요는 없었을 텐데요?","JPN":"あえて私にその真実を明かす必要はなかったはずです。","ENG":"You didn't have to tell me the truth.","TWN":"你沒必要告訴我真相吧？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저는 여전히 당신이 어디서 왔는지, 누구인지, 어떤 목적을 가졌는지 모릅니다.","JPN":"私は相変わらずあなたがどこから来たのか、何者なのか、どんな目的があるのか、わかりません。","ENG":"I still don't know where you're from, who you are, or what intentions you had when you came here.","TWN":"我不知道你來自哪裡，你是誰，有什麼樣的目的。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"하지만 지난 1년, 당신을 지켜본 결과 한 가지는 확신할 수 있었어요.","JPN":"ですが、この1年間あなたを見てきて、一つだけは確信できました。","ENG":"But after observing you for the past year, I became certain of one thing.","TWN":"但根據過去1年的時間裡對你的觀察，我可以確信一點。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신은 역시 틀림없는 델타 세븐의 일원이에요.","JPN":"あなたは間違いなくデルタセブンの一員です。","ENG":"You are, without a doubt, a member of Delta Seven.","TWN":"你一定也是第七三角洲部隊的一員。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"델타 세븐…….","JPN":"デルタセブン……","ENG":"Delta Seven...","TWN":"第七三角洲部隊……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그리고 저는 <color=#ffd34c>동료</color>라고 생각하는 사람을 속일 생각은 없습니다.","JPN":"そして私は、<color=#ffd34c>仲間</color>だと思う人を騙すつもりはありません。","ENG":"And I have no intention of deceiving someone I consider a <color=#ffd34c>comrade</color>.","TWN":"而且，我把你當成<color=#ffd34c>夥伴</color>，所以我不想欺騙你。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"하지만 기억이 없는 당신에게 제 생각을 강요할 생각도 없죠.","JPN":"同時に、記憶の無いあなたに私の意思を強要するつもりもありません。","ENG":"But I don't want to force my thoughts on someone who has no recollection of herself.","TWN":"但我不會將我的想法強加於失憶的你身上。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니 선택은 당신의 몫입니다, 안토노프.","JPN":"選択はあなた次第です、アントノフ。","ENG":"So, the choice is up to you, Antonov.","TWN":"選擇權在你手上，安東諾夫。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"군복을 벗고 남은 시간을 자유롭게 살 지, 아니면 우리와 함께 끝까지 싸울 지.","JPN":"軍から離れて残りの時間を自由に過ごすか、最後まで私たちと共に戦うか。","ENG":"Will you take off the uniform and live a free life, or will you fight alongside us until the bitter end?","TWN":"褪去軍裝，剩下的時間裡自由地生活，還是和我們一起並肩作戰到最後？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"저는…….","JPN":"私は……","ENG":"I–","TWN":"我……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"긴급 상황? 하루에 두 번씩이나?","JPN":"緊急事態？　一日に二度も？","ENG":"An emergency? Twice in one day?","TWN":"緊急狀況？今天發生的第二起嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"걱정하지 마세요.","JPN":"心配しないでください。","ENG":"Don't worry.","TWN":"不用擔心。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당장 이 자리에서 선택하라는 건 아닙니다.","JPN":"今すぐこの場で決めろとは言いません。","ENG":"I'm not asking you to answer right now.","TWN":"你不用馬上做出抉擇。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"하지만 마음의 준비가 된다면 언제든 제게 말씀해주세요.","JPN":"ですが、心の準備ができたら、いつでも私に言ってください。","ENG":"But please do whenever you are ready.","TWN":"但你要是準備好了，隨時可以跟我說。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_SIREN"}]`);export{e as default};